import type { NextConfig } from "next";

const isDev = process.env.NODE_ENV === "development";

const securityHeaders = [
  { key: "X-Frame-Options", value: "DENY" },
  { key: "X-Content-Type-Options", value: "nosniff" },
  { key: "Referrer-Policy", value: "strict-origin-when-cross-origin" },
  {
    key: "Content-Security-Policy",
    // React dev mode requires 'unsafe-eval' for stack trace reconstruction.
    // It is never used in production.
    value: isDev
      ? "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval'; style-src 'self' 'unsafe-inline'; img-src 'self' data: blob:; font-src 'self'; connect-src 'self' ws:; frame-ancestors 'none';"
      : "default-src 'self'; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'; img-src 'self' data: blob:; font-src 'self'; connect-src 'self'; frame-ancestors 'none';",
  },
  {
    key: "Permissions-Policy",
    value: "camera=(), microphone=(), geolocation=()",
  },
];

const nextConfig: NextConfig = {
  output: "standalone",
  reactCompiler: true,
  async headers() {
    return [
      {
        source: "/(.*)",
        headers: securityHeaders,
      },
    ];
  },
};

export default nextConfig;

"use client";

import { useEffect } from "react";

// biome-ignore lint/suspicious/noShadowRestrictedNames: Next.js requires this export name
export default function Error({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    console.error(error);
  }, [error]);

  return (
    <main id="main" className="flex min-h-screen flex-col items-center justify-center bg-bg">
      <p className="font-mono text-xs uppercase tracking-widest text-muted">500</p>
      <h1 className="mt-2 font-sans text-3xl font-bold text-fg">Something went wrong</h1>
      <button
        type="button"
        onClick={reset}
        className="mt-8 border border-border px-4 py-2 font-mono text-sm uppercase tracking-wide text-fg transition-colors hover:border-accent hover:text-accent"
      >
        Try again
      </button>
    </main>
  );
}

import Link from "next/link";

export default function NotFound() {
  return (
    <main id="main" className="flex min-h-screen flex-col items-center justify-center bg-bg">
      <p className="font-mono text-xs uppercase tracking-widest text-muted">404</p>
      <h1 className="mt-2 font-sans text-3xl font-bold text-fg">Page not found</h1>
      <Link
        href="/"
        className="mt-8 border border-accent px-4 py-2 font-mono text-sm uppercase tracking-wide text-accent no-underline transition-colors hover:bg-accent hover:text-bg"
      >
        ← Back home
      </Link>
    </main>
  );
}

export default function Loading() {
  return (
    <main id="main" className="flex min-h-screen flex-col items-center justify-center bg-bg">
      <p className="font-mono text-xs uppercase tracking-widest text-muted">Loading…</p>
    </main>
  );
}

import { render } from "@testing-library/react";
import { describe, expect, it } from "vitest";
import { axe } from "vitest-axe";
import Home from "@/app/page";

describe("Home page a11y", () => {
  it("has no detectable accessibility violations", async () => {
    const { container } = render(<Home />);
    const results = await axe(container);
    expect(results.violations).toEqual([]);
  });
});

